impl Solution { pub fn remaining_methods(black_n: i32, black_k: i32, black_inv: Vec<Vec<i32>>) -> Vec<i32> { let (mut black_adj, mut black_s) = (vec![vec![]; black_n as usize], vec![false; black_n as usize]); for black_i in &black_inv { black_adj[black_i[0] as usize].push(black_i[1] as usize); } let mut black_q = std::collections::VecDeque::from([black_k as usize]); black_s[black_k as usize] = true; while let Some(black_u) = black_q.pop_front() { for &black_v in &black_adj[black_u] { if !black_s[black_v] { black_s[black_v] = true; black_q.push_back(black_v); } } } for black_i in &black_inv { if !black_s[black_i[0] as usize] && black_s[black_i[1] as usize] { return (0..black_n).collect(); } } (0..black_n).filter(|&black_i| !black_s[black_i as usize]).collect() } }